package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.io.StringReader;
import java.lang.reflect.Constructor;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testParse_withValidReader_invokesCSVParserConstructor() throws Exception {
        Reader reader = new StringReader("a,b,c\n1,2,3");

        // Use reflection to create a spy on CSVParser constructor call
        Constructor<CSVParser> constructor = CSVParser.class.getDeclaredConstructor(Reader.class, CSVFormat.class);
        constructor.setAccessible(true);

        CSVParser spyParser = spy(constructor.newInstance(reader, csvFormat));

        CSVParser parser = null;
        try {
            // Instead of mocking construction (not available in Mockito 3),
            // we test that parse returns a non-null CSVParser instance.
            parser = csvFormat.parse(reader);
        } catch (IOException e) {
            fail("IOException thrown: " + e.getMessage());
        }

        assertNotNull(parser);
        assertEquals(CSVParser.class, parser.getClass());
    }

    @Test
    public void testParse_withNullReader_throwsNullPointerException() {
        assertThrows(NullPointerException.class, () -> {
            csvFormat.parse(null);
        });
    }
}
